void _navigateTo(int page) {
  final diff = (page - _currentPage).abs();

  if (diff > 1) {
    // Lompat > 1 halaman ŌåÆ jumpToPage (tanpa animasi scroll)
    _pageController.jumpToPage(page);
  } else {
    // Sequential ŌåÆ animateToPage (halus)
    _pageController.animateToPage(page, duration: 300ms, ...);
  }
}
```

